func TestEnumWebhookStatusEnum(t *testing.T) {
	t.Run("NewFromString_active", func(t *testing.T) {
		t.Parallel()
		val, err := NewWebhookStatusEnumFromString("active")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, WebhookStatusEnum("active"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_paused", func(t *testing.T) {
		t.Parallel()
		val, err := NewWebhookStatusEnumFromString("paused")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, WebhookStatusEnum("paused"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_disabled", func(t *testing.T) {
		t.Parallel()
		val, err := NewWebhookStatusEnumFromString("disabled")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, WebhookStatusEnum("disabled"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewWebhookStatusEnumFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewWebhookStatusEnumFromString("active")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

